/* Procedure structure for procedure `importar_tabelas_genesis` */

/*!50003 DROP PROCEDURE IF EXISTS  `importar_tabelas_genesis` */;

DELIMITER $$

/*!50003 CREATE DEFINER=`root`@`localhost` PROCEDURE `importar_tabelas_genesis`(IN p_banco TEXT, OUT v_debug TEXT)
BEGIN
 DECLARE v_controle_1 INTEGER DEFAULT 0;
 DECLARE v_controle_2 INTEGER DEFAULT 0;
 DECLARE v_controle_3 INTEGER DEFAULT 0;
 DECLARE v_controle_4 INTEGER DEFAULT 0;
 DECLARE v_controle_5 INTEGER DEFAULT 0;
 DECLARE v_setCodigo INT DEFAULT NULL;
 DECLARE v_setSetor TEXT DEFAULT NULL;
 DECLARE v_setEmail TEXT DEFAULT NULL;
 DECLARE v_setEndereco TEXT DEFAULT NULL;
 DECLARE v_setTel TEXT DEFAULT NULL;
 DECLARE v_setCep TEXT DEFAULT NULL;
 DECLARE v_setFax TEXT DEFAULT NULL;
 DECLARE v_espCodigo INT DEFAULT NULL;
 DECLARE v_espDescricao TEXT DEFAULT NULL;
 DECLARE v_espCboCodigo TEXT DEFAULT NULL;
 DECLARE v_espStatus TEXT DEFAULT NULL;
 DECLARE v_proCodigo INT DEFAULT NULL;
 DECLARE v_proNome TEXT DEFAULT NULL;
 DECLARE v_proTel1 TEXT DEFAULT NULL;
 DECLARE v_proTel2 TEXT DEFAULT NULL;
 DECLARE v_proRg TEXT DEFAULT NULL;
 DECLARE v_proCpf TEXT DEFAULT NULL;
 DECLARE v_itProEspEspCodigo INT DEFAULT NULL;
 DECLARE v_itProEspProfCodigo INT DEFAULT NULL;
 DECLARE v_itEspSetSetCodigo INT DEFAULT NULL;
 DECLARE v_tipRegDescricao TEXT DEFAULT NULL;
 DECLARE v_itProEspCrmNumero TEXT DEFAULT NULL;
 
 DECLARE v_usuCodigo INT DEFAULT NULL;
 DECLARE v_usuNome TEXT DEFAULT NULL;
 DECLARE v_usuLogin TEXT DEFAULT NULL;
 DECLARE v_usuSenha TEXT DEFAULT NULL;
 DECLARE v_usuSetCodigo INT DEFAULT NULL;
 
 block_setor: BEGIN
		 DECLARE c_setor CURSOR FOR
				SELECT setCodigo, setSetor, setEmail, setEndereco, setTel, setCep, setFax
				FROM tmp_setor s_gen
				WHERE NOT EXISTS (SELECT 1 FROM setor s WHERE s.setCodigo = s_gen.setCodigo);
		 DECLARE CONTINUE HANDLER FOR NOT FOUND SET v_controle_1 = 1;
		 
		 SET @SQLStmt = CONCAT('DROP TEMPORARY TABLE IF EXISTS tmp_setor');
		 PREPARE Stmt FROM @SQLStmt;
		 EXECUTE Stmt;
		 DEALLOCATE PREPARE Stmt;
		 
		 SET @SQLStmt = CONCAT('CREATE TEMPORARY TABLE tmp_setor SELECT * FROM ',p_banco,'.setor WHERE setTipoUnidade = \'ENTIDADES\'');
		 PREPARE Stmt FROM @SQLStmt;
		 EXECUTE Stmt;
		 DEALLOCATE PREPARE Stmt;
		 
		 
		 OPEN c_setor;
			REPEAT
			FETCH c_setor INTO v_setCodigo, v_setSetor, v_setEmail, v_setEndereco, v_setTel, v_setCep, v_setFax;
				IF NOT v_controle_1 THEN
				
				INSERT INTO setor(setCodigo, setDescricao, setEmail, setEndereco, setTelefone, dataHoraCad, codUsuario, codSetor, dtaHoraAtualizacao, setImgDepto, setImgBrasao)
				VALUES (v_setCodigo,v_setSetor,v_setEmail,v_setEndereco,v_setTel,NOW(),1,1,NOW(),NULL,NULL);
				INSERT INTO entidade (descricao, dataHoraCad, entCEP, entTelefone, entEmail, entFax, codUsuario, codSetor, dtaHoraCadastro, dtaHoraAtualizacao, entSetCodigo)
				VALUES (v_setSetor,NOW(),v_setCep,v_setTel,v_setEmail,v_setFax,1,1,NOW(),NOW(),v_setCodigo);
				END IF;
			UNTIL v_controle_1 END REPEAT;
		 CLOSE c_setor;
 END block_setor;
 
 block_especialidade: BEGIN
		 DECLARE c_especialidade CURSOR FOR
				SELECT espCodigo, espDescricao, cbo, espStatus
				FROM tmp_especialidade e_gen
				WHERE NOT EXISTS (SELECT 1 FROM especialidade e WHERE e.espCodigo = e_gen.espCodigo);
		 DECLARE CONTINUE HANDLER FOR NOT FOUND SET v_controle_2 = 1;
		 SET @SQLStmt = CONCAT('DROP TEMPORARY TABLE IF EXISTS tmp_especialidade');
		 PREPARE Stmt FROM @SQLStmt;
		 EXECUTE Stmt;
		 DEALLOCATE PREPARE Stmt;
		 SET @SQLStmt = CONCAT('CREATE TEMPORARY TABLE tmp_especialidade SELECT espCodigo, espDescricao, (espCboCodigo+0)cbo, espStatus FROM ',p_banco,'.especialidade_cbo');
		 PREPARE Stmt FROM @SQLStmt;
		 EXECUTE Stmt;
		 DEALLOCATE PREPARE Stmt;
		 SET v_debug = '';
		 OPEN c_especialidade;
			REPEAT
			FETCH c_especialidade INTO v_espCodigo,v_espDescricao,v_espCboCodigo,v_espStatus;
				IF NOT v_controle_2 THEN
				SET v_debug = v_espCboCodigo;
				INSERT INTO especialidade(espCodigo, espDescricao, espCodigoCbo, espStatus, codUsuario, codSetor, dtaHoraCadastro, dtaHoraAtualizacao)
				VALUES (v_espCodigo,v_espDescricao,v_espCboCodigo,v_espStatus,1,1,NOW(),NOW());
			END IF;
			UNTIL v_controle_2 END REPEAT;
		 CLOSE c_especialidade;
 END block_especialidade;
 block_profissional: BEGIN
		 DECLARE c_profissional CURSOR FOR
				SELECT proCodigo, proNome, proTel1, proTel2, proRg, proCpf
				FROM tmp_profissional p_gen
				WHERE NOT EXISTS (SELECT 1 FROM profissional p WHERE p.proCodigo = p_gen.proCodigo);
		 DECLARE CONTINUE HANDLER FOR NOT FOUND SET v_controle_3 = 1;
		 SET @SQLStmt = CONCAT('DROP TEMPORARY TABLE IF EXISTS tmp_profissional');
		 PREPARE Stmt FROM @SQLStmt;
		 EXECUTE Stmt;
		 DEALLOCATE PREPARE Stmt;
		 SET @SQLStmt = CONCAT('CREATE TEMPORARY TABLE tmp_profissional
								SELECT * FROM ',p_banco,'.profissional
								WHERE EXISTS (SELECT 1 FROM ',p_banco,'.itens_profissional_especialidade ipe, ',p_banco,'.itens_especialidade_setor ies
											  WHERE itproespprofcodigo = proCodigo AND itespsetespcodigo = itproespcodigo
											  AND itproespespcodigo IS NOT NULL
											  AND itProEspEspCodigo > 0
											  AND EXISTS (SELECT 1 FROM ',p_banco,'.setor WHERE itespsetsetcodigo = setCodigo AND setTipoUnidade = \'ENTIDADES\'))');
		 PREPARE Stmt FROM @SQLStmt;
		 EXECUTE Stmt;
		 DEALLOCATE PREPARE Stmt;
		 
		 OPEN c_profissional;
			REPEAT
			FETCH c_profissional INTO v_proCodigo, v_proNome, v_proTel1, v_proTel2, v_proRg, v_proCpf;
				IF NOT v_controle_3 THEN
				
				INSERT INTO profissional(proCodigo, proNome, proTelefone, proCelular, proRG, proCPF, codUsuario, codSetor, dtaHoraCadastro, dtaHoraAtualizacao)
				VALUES (v_proCodigo,v_proNome,v_proTel1,v_proTel2,v_proRg,v_proCpf,1,1,NOW(),NOW());
			END IF;
			UNTIL v_controle_3 END REPEAT;
		 CLOSE c_profissional;
 END block_profissional;
 
 block_itens: BEGIN
		DECLARE c_itens CURSOR FOR
		SELECT itProEspEspCodigo, itProEspProfCodigo, itEspSetSetCodigo, tipRegDescricao, itProEspCrmNumero
		FROM tmp_itens_profissional_especialidade_setor i_gen
		WHERE NOT EXISTS (SELECT 1 FROM especialidadeprofissional e WHERE e.espProEspecialidade = i_gen.itProEspEspCodigo
															  AND e.espProProfissional = i_gen.itProEspProfCodigo
															  AND e.espProSetCodigo = i_gen.itEspSetSetCodigo);
		DECLARE CONTINUE HANDLER FOR NOT FOUND SET v_controle_4 = 1;
		SET @SQLStmt = CONCAT('DROP TEMPORARY TABLE IF EXISTS tmp_itens_profissional_especialidade_setor');
		PREPARE Stmt FROM @SQLStmt;
		EXECUTE Stmt;
		DEALLOCATE PREPARE Stmt;
		SET @SQLStmt = CONCAT('CREATE TEMPORARY TABLE tmp_itens_profissional_especialidade_setor
						 SELECT itProEspEspCodigo, itProEspProfCodigo, itEspSetSetCodigo, tipRegDescricao, itProEspCrmNumero
						 FROM ',p_banco,'.itens_profissional_especialidade ipe, ',p_banco,'.itens_especialidade_setor ies, ',p_banco,'.tiporegistro t, profissional p
						 WHERE itespsetespcodigo = itproespcodigo
						 AND itproespprofcodigo = proCodigo
						 AND itproesptipo = tipregcodigo
						 AND itproespespcodigo IS NOT NULL
						 AND itProEspEspCodigo > 0
						 AND EXISTS (SELECT 1 FROM ',p_banco,'.setor WHERE itespsetsetcodigo = setCodigo AND setTipoUnidade = \'ENTIDADES\')');
		PREPARE Stmt FROM @SQLStmt;
		EXECUTE Stmt;
		DEALLOCATE PREPARE Stmt;
		OPEN c_itens;
			REPEAT
			FETCH c_itens INTO v_itProEspEspCodigo, v_itProEspProfCodigo, v_itEspSetSetCodigo, v_tipRegDescricao, v_itProEspCrmNumero;
				IF NOT v_controle_4 THEN
				INSERT INTO especialidadeprofissional(espProEspecialidade, espProProfissional, espProSetor, espProStatus, espProTipoRegistro, espProNumeroRegistro, codUsuario, codSetor, dtaHoraCadastro, dtaHoraAtualizacao, espProSetCodigo)
				VALUES (v_itProEspEspCodigo, v_itProEspProfCodigo, v_itEspSetSetCodigo, 'ATIVO', v_tipRegDescricao, v_itProEspCrmNumero, 1, 1, NOW(), NOW(), v_itEspSetSetCodigo);
				END IF;
			UNTIL v_controle_4 END REPEAT;
		CLOSE c_itens;
 END block_itens;
 
 block_usuario: BEGIN
		DECLARE c_usuario CURSOR FOR
		SELECT *
		FROM tmp_usuario u_gen
		WHERE NOT EXISTS (SELECT 1 FROM usuario u WHERE u.usuCodigo = u_gen.usuCodigo);
		DECLARE CONTINUE HANDLER FOR NOT FOUND SET v_controle_5 = 1;
		SET @SQLStmt = CONCAT('DROP TEMPORARY TABLE IF EXISTS tmp_usuario');
		PREPARE Stmt FROM @SQLStmt;
		EXECUTE Stmt;
		DEALLOCATE PREPARE Stmt;
		
		SET @SQLStmt = CONCAT('CREATE TEMPORARY TABLE tmp_usuario
						 SELECT usuCodigo, usuNome, usuLogin, usuSenha, usuSetCodigo
						 FROM ',p_banco,'.usuario u
						 WHERE EXISTS (SELECT 1 FROM ',p_banco,'.setor WHERE u.usuSetCodigo = setCodigo AND setTipoUnidade = \'ENTIDADES\')');
		PREPARE Stmt FROM @SQLStmt;
		EXECUTE Stmt;
		DEALLOCATE PREPARE Stmt;
		
		OPEN c_usuario;
			REPEAT
			FETCH c_usuario INTO v_usuCodigo, v_usuNome, v_usuLogin, v_usuSenha, v_usuSetCodigo;
				IF NOT v_controle_5 THEN
				
				INSERT INTO usuario(usuCodigo, usuNome, usuLogin, usuSenha, usuSetCodigo, dataHoraCad, codUsuario, codSetor, dtaHoraAtualizacao, usuSetor)
				VALUES (v_usuCodigo, v_usuNome, v_usuLogin, v_usuSenha, v_usuSetCodigo, NOW(), 1, 1, NOW(), v_usuSetCodigo);
				END IF;
			UNTIL v_controle_5 END REPEAT;
		CLOSE c_usuario;
 END block_usuario;
END */$$
DELIMITER ;

